  }
}

PORTUGUÊS BRASILEIRO. Casos realistas. DSM-5-TR. ESCOLHA 1 FORMATO ALEATORIAMENTE.`
        },
        {
          role: "user",
          content: `Gere caso: level=${level}, category=${category}. APENAS JSON.`
        }
      ]
    });

    const caseData = JSON.parse(completion.choices[0].message.content);

