      acc[skill.module].push(skill);
      return acc;
    }, {});

    logger.debug(`[Skills] ✅ ${skills.length} habilidades encontradas`);

    res.json({
      success: true,
      skills: skills,
      skills_by_module: grouped,
      total: skills.length
