 */
function getICCTier(iccScore) {
    if (iccScore >= 86) return { tier: 6, label: 'Mestre', color: '#DC2626' };
    if (iccScore >= 71) return { tier: 5, label: 'Especialista', color: '#D97706' };
    if (iccScore >= 51) return { tier: 4, label: 'Clínico Confiante', color: '#7C3AED' };
    if (iccScore >= 31) return { tier: 3, label: 'Praticante', color: '#2563EB' };
    if (iccScore >= 16) return { tier: 2, label: 'Aprendiz', color: '#059669' };
    return { tier: 1, label: 'Iniciante', color: '#6B7280' };
}

