/**
 * Streak Service
 * Gerencia a lógica de sequência de dias consecutivos (Streaks)
 */
const { getFromBoostspace, updateInBoostspace } = require('./database');
const logger = require('../config/logger');

// Mapa de timezone para garantir consistência (Brasil)
const TIMEZONE = 'America/Sao_Paulo';

/**
 * Obtém a data atual no formato YYYY-MM-DD
 */
function getTodayDate() {
    return new Date().toLocaleDateString('en-CA', { timeZone: TIMEZONE }); // YYYY-MM-DD
}

/**
 * Calcula a diferença em dias entre duas datas (strings YYYY-MM-DD)
 */
function getDaysDifference(date1, date2) {
    const d1 = new Date(date1);
    const d2 = new Date(date2);
    const diffTime = Math.abs(d2 - d1);
    return Math.ceil(diffTime / (1000 * 60 * 60 * 24));
}

/**
 * Verifica e atualiza o streak do usuário
 * @param {string} userId - ID do usuário
 * @param {string} activityType - Tipo de atividade (login, challenge, diagnostic, conceptualization)
 */
async function checkAndUpdateStreak(userId, activityType = 'login') {
    try {
        // 1. Buscar usuário
        const users = await getFromBoostspace('users', { id: userId });
        if (!users || users.length === 0) return null;

        const user = users[0];
        const today = getTodayDate();

        // Se last_activity_at não existe, é o primeiro dia
        // Se for timestamp, converter para data YYYY-MM-DD
        let lastActivityDate = null;

        if (user.last_activity_at) {
            lastActivityDate = new Date(user.last_activity_at).toLocaleDateString('en-CA', { timeZone: TIMEZONE });
        }

        // Se já fez atividade hoje, não precisa atualizar streak (mas atualiza timestamp)
        if (lastActivityDate === today) {
            logger.info('🔥 Streak: Atividade já registrada hoje', { userId, today });
            return {
                current_streak: user.current_streak || 0,
                streak_updated: false
            };
        }

        let currentStreak = user.current_streak || 0;
        let maxStreak = user.max_streak || 0;
        let streakUpdated = false;
        let streakBroken = false;

        if (!lastActivityDate) {
            // Primeira vez que registra
            currentStreak = 1;
            streakUpdated = true;
        } else {
            const diffDays = getDaysDifference(lastActivityDate, today);

            if (diffDays === 1) {
                // Sequência mantida! (Ontem -> Hoje)
                currentStreak++;
                streakUpdated = true;
            } else if (diffDays > 1) {
                // Quebrou a sequência
                currentStreak = 1; // Reinicia contando hoje
                streakBroken = true;
                streakUpdated = true;
            }
            // Se diffDays === 0 já tratamos acima
        }

        // Atualizar recorde
        if (currentStreak > maxStreak) {
            maxStreak = currentStreak;
        }

        // Salvar atualização apenas se mudou algo
        if (streakUpdated || !lastActivityDate) {
            const updateData = {
                current_streak: currentStreak,
                max_streak: maxStreak,
                last_activity_at: new Date().toISOString()
            };

            await updateInBoostspace('users', userId, updateData);

            logger.info('🔥 Streak Atualizado', {
                userId,
                oldStreak: user.current_streak,
                newStreak: currentStreak,
                broken: streakBroken
            });

            return {
                current_streak: currentStreak,
                max_streak: maxStreak,
                streak_updated: true,
                streak_broken: streakBroken,
                days_gained: streakUpdated ? 1 : 0
            };
        }

        return { current_streak: currentStreak, streak_updated: false };

    } catch (error) {
        logger.error('❌ Erro ao atualizar streak', { error: error.message, userId });
        // Não lança erro para não quebrar o fluxo principal
        return null;
    }
}

/**
 * Obtém dados de streak do usuário
 */
async function getUserStreak(userId) {
    try {
        const users = await getFromBoostspace('users', { id: userId });
        if (!users || users.length === 0) return { current_streak: 0, max_streak: 0 };

        const user = users[0];
        const today = getTodayDate();
        let lastActivityDate = null;

        if (user.last_activity_at) {
            lastActivityDate = new Date(user.last_activity_at).toLocaleDateString('en-CA', { timeZone: TIMEZONE });
        }

        // Verificar se streak está "em risco" (ontem foi último dia, hoje ainda não fez)
        // Se última atividade foi anteontem ou antes, streak já é visualmente 0 (ou será resetado na próxima ação)
        let displayStreak = user.current_streak || 0;
        let isFrozen = false; // Implementar freeze depois

        if (lastActivityDate) {
            const diffDays = getDaysDifference(lastActivityDate, today);
            if (diffDays > 1) {
                // Visualmente já quebrou, embora no banco só atualize na próxima ação
                displayStreak = 0;
            }
        } else {
            displayStreak = 0;
        }

        return {
            current_streak: displayStreak,
            max_streak: user.max_streak || 0,
            last_activity_date: lastActivityDate,
            today
        };

    } catch (error) {
        logger.error('❌ Erro ao obter streak', { error: error.message, userId });
        return { current_streak: 0, max_streak: 0 };
    }
}

module.exports = {
    checkAndUpdateStreak,
    getUserStreak
};

/**
 * Socket.io Chat Handler
 * Gerencia comunicação real-time do chat
 */

const logger = require('../config/logger');
const { sendMessage, getOrCreateThread, routeToAssistant } = require('../services/openai-service');
const { verifyToken } = require('../middleware/auth');
const { createClient } = require('@supabase/supabase-js');

const supabase = createClient(
  process.env.SUPABASE_URL,
  process.env.SUPABASE_SERVICE_ROLE_KEY
);

// Store de conexões ativas (userId -> socketId)
const activeConnections = new Map();

/**
 * Inicializar handlers do Socket.io
 */
function initializeSocketHandlers(io) {
  
  // Middleware de autenticação
  io.use(async (socket, next) => {
    try {
      const token = socket.handshake.auth.token;
      
      if (!token) {
        return next(new Error('Token não fornecido'));
      }

      const decoded = verifyToken(token);
      socket.userId = decoded.userId;
      socket.userPlan = decoded.plan;
      
      logger.info('Cliente autenticado no WebSocket', { 
        userId: socket.userId,
        socketId: socket.id 
      });
      
      next();
    } catch (error) {
      logger.error('Erro auth WebSocket', { error: error.message });
      next(new Error('Autenticação falhou'));
    }
  });

  io.on('connection', (socket) => {
    const userId = socket.userId;
    
    logger.info('Cliente conectado', { userId, socketId: socket.id });
    
    // Adicionar ao store de conexões
    activeConnections.set(userId, socket.id);
    
    // Join room privado do usuário
    socket.join(`user:${userId}`);

    /**
     * Evento: send_message
     * Cliente envia mensagem para assistente
     */
    socket.on('send_message', async (data) => {
      try {
        const { message, assistantType, conversationId } = data;

        logger.info('Mensagem recebida via WebSocket', {
          userId,
          assistantType,
          messageLength: message.length
        });

        // Validar rate limiting baseado no plano
        const rateLimitOk = await checkRateLimit(userId, socket.userPlan);
        if (!rateLimitOk) {
          return socket.emit('error', {
            message: 'Limite de mensagens excedido para seu plano',
            code: 'RATE_LIMIT_EXCEEDED'
          });
        }

        // Confirmar recebimento
        socket.emit('message_received', {
          status: 'processing',
          timestamp: new Date().toISOString()
        });

        // Indicar que assistente está "digitando"
        socket.emit('assistant_typing', {
          assistantType
        });

        // Rotear para assistente apropriado se não especificado
        const targetAssistant = assistantType || routeToAssistant(message);

        // Get ou criar thread
        const threadId = await getOrCreateThread(userId, targetAssistant, conversationId);

        // Enviar mensagem para OpenAI (isso pode demorar 10-60s)
        const response = await sendMessage(threadId, targetAssistant, message, userId);

        // Enviar resposta ao cliente
        socket.emit('message_response', {
          response: response.response,
          threadId: response.threadId,
          conversationId: conversationId || response.threadId,
          assistantType: targetAssistant,
          tokensUsed: response.tokensUsed,
          timestamp: response.timestamp
        });

        logger.info('Mensagem processada e enviada', {
          userId,
          tokensUsed: response.tokensUsed
        });

      } catch (error) {
        logger.error('Erro ao processar mensagem', {
          error: error.message,
          userId
        });

        socket.emit('error', {
          message: 'Erro ao processar mensagem',
          code: 'PROCESSING_ERROR',
          details: error.message
        });
      }
    });

    /**
     * Evento: stop_typing
     * Cliente parou de digitar (feedback UX)
     */
    socket.on('stop_typing', () => {
      // Apenas log por ora, pode usar para indicadores UX futuros
      logger.debug('Cliente parou de digitar', { userId });
    });

    /**
     * Evento: disconnect
     * Cliente desconectou
     */
    socket.on('disconnect', (reason) => {
      logger.info('Cliente desconectado', {
        userId,
        socketId: socket.id,
        reason
      });

      // Remover do store
      activeConnections.delete(userId);
    });

  });

  logger.info('✅ Socket.io handlers inicializados');
}

/**
 * Check rate limiting baseado no plano do usuário
 * ✅ IMPLEMENTADO com Supabase
 */
async function checkRateLimit(userId, plan) {
  try {
    const limits = {
      free: 20,      // 20 mensagens/dia
      basic: 100,    // 100 mensagens/dia
      pro: 500,      // 500 mensagens/dia
      premium: 9999  // Ilimitado
    };

    const userLimit = limits[plan] || limits.free;
    const today = new Date().toISOString().split('T')[0]; // YYYY-MM-DD

    // Buscar contador de mensagens de hoje
    const { data: rateData, error: fetchError } = await supabase
      .from('user_rate_limits')
      .select('*')
      .eq('user_id', userId)
      .eq('date', today)
      .single();

    if (fetchError && fetchError.code !== 'PGRST116') { // PGRST116 = not found
      logger.error('Erro ao buscar rate limit', { error: fetchError.message });
      return true; // Em caso de erro, permitir (fail-open)
    }

    // Se não existe registro de hoje, criar
    if (!rateData) {
      await supabase
        .from('user_rate_limits')
        .insert({
          user_id: userId,
          date: today,
          message_count: 1,
          plan: plan
        });

      logger.info('Rate limit: primeiro uso hoje', { userId, plan });
      return true;
    }

    // Verificar se ultrapassou limite
    if (rateData.message_count >= userLimit) {
      logger.warn('Rate limit excedido', {
        userId,
        plan,
        count: rateData.message_count,
        limit: userLimit
      });
      return false;
    }

    // Incrementar contador
    await supabase
      .from('user_rate_limits')
      .update({ message_count: rateData.message_count + 1 })
      .eq('user_id', userId)
      .eq('date', today);

    logger.info('Rate limit OK', {
      userId,
      count: rateData.message_count + 1,
      limit: userLimit
    });

    return true;

  } catch (error) {
    logger.error('Erro no rate limiting', { error: error.message });
    return true; // Fail-open: se erro, permitir
  }
}

/**
 * Enviar notificação para usuário específico
 * (útil para webhooks de pagamento, badges desbloqueados, etc)
 */
function sendNotificationToUser(userId, notification) {
  const socketId = activeConnections.get(userId);
  
  if (socketId) {
    const io = require('../server').io;
    io.to(socketId).emit('notification', notification);
    logger.info('Notificação enviada', { userId, type: notification.type });
  }
}

module.exports = {
  initializeSocketHandlers,
  sendNotificationToUser
};
